package tests;import base.BaseTest;import pages.AdminPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP07FiltrarPedidosTodosTest extends BaseTest {    @Test    void administradorFiltraPedidosDelDiaPorEstadoTodos() {        try {            System.out.println("Ejecutando HP-07: Administrador filtra pedidos del día por estado Todos");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("admin", "admin");            Thread.sleep(3000);            AdminPage adminPage = new AdminPage(driver);            Assertions.assertTrue(                    adminPage.panelAdministradorVisible(),                    "No se visualiza el Panel Administrador después del inicio de sesión."            );            adminPage.seleccionarEstadoTodos();            adminPage.filtrar();            Thread.sleep(3000);            Assertions.assertTrue(                    adminPage.estadisticasVisibles(),                    "No se visualizan las estadísticas del día después de filtrar."            );            Assertions.assertTrue(                    adminPage.tablaPedidosVisible(),                    "No se visualiza la tabla de pedidos después de filtrar por estado Todos."            );            System.out.println("HP-07 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-07: " + e.getMessage());        }    }}